class Solution {
public:
    string reverseParentheses(string s) {
        stack<char> st;
        for (char c : s) {
            if (c == '(') {
                st.push(c);
            } else if (c == ')') {
                while (st.top() != '(') {
                    s[st.top() - 'a'] = st.top();
                    st.pop();
                }
                st.pop();
            } else {
                st.push(c);
            }
        }
        return s;
    }
};
